#[derive(ClapParser, Debug)]
struct Args {
    #[arg(short)]
    input_file_path: PathBuf,
    #[arg(short)]
    output_file_path: PathBuf,
}

/// Given a file in the format above, combine all the counts [year,COUNT,num_books]
/// then combine all the capitalizations of all words into one, leaving you with a
/// final format of [word] [total_count]
///
/// Assume file is sorted alphabetically without respect to case-sensitivity
fn main() -> Result<()> {
    let args = Args::parse();

    let input_file_path = if args.input_file_path.is_relative() {
        std::env::current_dir().unwrap().join(args.input_file_path)
    } else {
        args.input_file_path
    };

    let output_file_path = if args.output_file_path.is_relative() {
        std::env::current_dir().unwrap().join(args.output_file_path)
    } else {
        args.output_file_path
    };

    let mut reader = BufReader::new(File::open(input_file_path)?);

    let mut output_file = File::options()
        .create(true)
        .truncate(true)
        .write(true)
        .open(output_file_path)?;

    let mut line = String::new();

    let mut current_word = String::new();
    let mut current_count = 0usize;

    loop {
        line.clear();
        let num_bytes = reader.read_line(&mut line)?;
        if num_bytes == 0 {
            break;
        }

        let (_, n_gram_line) = all_consuming(parse_line)
            .parse(&line)
            .expect("should parse");

        if n_gram_line.word != current_word {
            if !current_word.is_empty() {
                writeln!(output_file, "{} {}", current_word, current_count)?;
            }

            current_word = n_gram_line.word.to_string();
            current_count = n_gram_line.count;
        } else {
            current_count += n_gram_line.count;
        }
    }

    writeln!(output_file, "{} {}", current_word, current_count)?;

    Ok(())
}

#[derive(Debug, Clone)]
struct NGramLine {
    word: String,
    count: usize,
}

fn parse_line(input: &str) -> IResult<&str, NGramLine> {
    let (input, (word, count_list)) = terminated(
        separated_pair(
            alpha1,
            space1,
            separated_list1(
                space1,
                (
                    complete::usize,
                    tag(","),
                    complete::usize,
                    tag(","),
                    complete::usize,
                ),
            ),
        ),
        opt(line_ending),
    )
    .parse(input)?;

    Ok((
        input,
        NGramLine {
            word: word.to_lowercase(),
            count: count_list
                .into_iter()
                .map(|(_year, _, word_count, _, _book_count)| word_count)
                .sum(),
        },
    ))
}
